(()=>{"use strict";const Triggers=new Map;class Trigger{static replaceVariables=input=>{const stringPlaceholders=[];const commentPlaceholders=[];const templatePlaceholders=[];const commentPattern=/(\/\*[\s\S]*?\*\/|\/\/.*)/g;const inputWithoutComments=input.replace(commentPattern,(match=>{commentPlaceholders.push(match);return`@@COMMENT_PLACEHOLDER_${commentPlaceholders.length}@@`}));const templatePattern=/(`(?:\\[\s\S]|[^\\`])*?`)/g;const inputWithoutTemplates=inputWithoutComments.replace(templatePattern,(match=>{templatePlaceholders.push(match);return`@@TEMPLATE_PLACEHOLDER_${templatePlaceholders.length}@@`}));const stringPattern=/(["'])(?:\\.|[^\\])*?\1/g;const inputWithoutStrings=inputWithoutTemplates.replace(stringPattern,(match=>{stringPlaceholders.push(match);return`@@STRING_PLACEHOLDER_${stringPlaceholders.length}@@`}));const processedInput=inputWithoutStrings.replace(/(?<=[\s\n\t{}()\[\],;<>!=+\-*/%:|&]|^)\b(year|month|day|hour|minute|lastUpdate|weekday|isInRange)\b/g,(match=>`this.${match}`)).replace(/(?<=[\s\n\t{}()\[\],;<>!=+\-*/%:|&]|^)\$(\w+)\b/g,((match,variable)=>`State.variables.${variable}`)).replace(/(?<=[\s\n\t{}()\[\],;<>!=+\-*/%:|&]|^)_(\w+)\b/g,((match,variable)=>`State.temporary.${variable}`));const restoredStrings=processedInput.replace(/@@STRING_PLACEHOLDER_(\d+)@@/g,((match,index)=>stringPlaceholders[index-1]));const restoredComments=restoredStrings.replace(/@@COMMENT_PLACEHOLDER_(\d+)@@/g,((match,index)=>commentPlaceholders[index-1]));return restoredComments.replace(/@@TEMPLATE_PLACEHOLDER_(\d+)@@/g,((match,index)=>templatePlaceholders[index-1]))};static add(id,condition,callback,single=false){const replacedCondition=Trigger.replaceVariables(condition.toString());const replacedCallback=Trigger.replaceVariables(callback.toString());Triggers.set(id,{condition:replacedCondition,callback:replacedCallback,single:single,sugar:false})}static addSugar(id,condition,callback,single=false){const replacedCondition=Trigger.replaceVariables(condition.toString());Triggers.set(id,{condition:replacedCondition,callback:callback.toString(),single:single,sugar:true})}}class Clock{static varName="$clock";static weekdays=["星期日","星期一","星期二","星期三","星期四","星期五","星期六"];constructor(year=2024,month=1,day=1,hour=1,minute=1){this.year=year;this.month=month;this.day=day;this.hour=hour;this.minute=minute;this.lastUpdate={year:year,month:month,day:day,hour:hour,minute:minute}}getDaysInMonth(year=this.year,month=this.month){const daysInMonth=[31,Clock.isLeapYear(year)?29:28,31,30,31,30,31,31,30,31,30,31];return daysInMonth[month-1]}getFormattedTime(){return`${this.year}-${Clock.formatTwoDigits(this.month)}-${Clock.formatTwoDigits(this.day)} ${Clock.formatTwoDigits(this.hour)}:${Clock.formatTwoDigits(this.minute)}`}carryOverTime(){if(this.minute>=60){this.hour+=Math.floor(this.minute/60);this.minute%=60}if(this.hour>=24){this.day+=Math.floor(this.hour/24);this.hour%=24}while(this.day>this.getDaysInMonth()){this.day-=this.getDaysInMonth();this.month++;if(this.month>12){this.month=1;this.year++}}}updateLastTime(){this.lastUpdate={year:this.year,month:this.month,day:this.day,hour:this.hour,minute:this.minute}}get timeDiff(){const prev=new Date(this.lastUpdate.year,this.lastUpdate.month-1,this.lastUpdate.day,this.lastUpdate.hour,this.lastUpdate.minute);const current=new Date(this.year,this.month-1,this.day,this.hour,this.minute);return(current-prev)/6e4}get daysDiff(){const current=new Date(this.year,this.month-1,this.day);const lastUpdate=new Date(this.lastUpdate.year,this.lastUpdate.month-1,this.lastUpdate.day);const timeDiff=Math.abs(current-lastUpdate);return Math.ceil(timeDiff/(1e3*60*60*24))}parseDateTime(dateStr,timeStr){let[year,month,day]=[this.year,this.month,this.day];if(dateStr){[year,month,day]=dateStr.split("-").map(Number)}const[hour,minute]=timeStr.split(":").map(Number);return new Date(year,month-1,day,hour,minute)}parseTimeRange(rangeStr){const regexFull=/(\d{4}-\d{1,2}-\d{1,2})?\s*(\d{2}:\d{2})?\s*to\s*(\d{4}-\d{1,2}-\d{1,2})?\s*(\d{2}:\d{2})?/;const match=rangeStr.match(regexFull);if(!match){throw new Error("Invalid time range format")}let[_,startDate,startTime,endDate,endTime]=match;const startDateTime=this.parseDateTime(startDate,startTime||"00:00");const endDateTime=this.parseDateTime(endDate||startDate,endTime||"23:59");return{start:startDateTime,end:endDateTime}}isInRange(rangeStr){const{start:start,end:end}=this.parseTimeRange(rangeStr);const currentTime=new Date(this.year,this.month-1,this.day,this.hour,this.minute);return currentTime>=start&&currentTime<=end}addMinutes(minutes){this.minute+=minutes;this.carryOverTime();this.checkTriggers();this.updateLastTime()}addHours(hours){this.addMinutes(hours*60)}addDays(days){this.addMinutes(days*24*60)}addMonths(months){let days=0;let year=this.year;let month=this.month;repeat(months,(_i=>{if(month>=12){month=1;year+=1}else if(_i!==0){month+=1}days+=this.getDaysInMonth(year,month)}));this.addDays(days)}addYears(years){this.addDays(years*(Clock.isLeapYear(this.year)?366:365))}checkTriggers(){const td=this.timeDiff;const dd=this.daysDiff;for(const[key,trigger]of Triggers){const isExec=eval(trigger.condition);if(isExec){try{if(trigger.sugar){$.wiki(trigger.callback)}else{eval(`(${trigger.callback})`)()}}catch(e){alert(`An error occurred in the trigger with ID \`${key}\`. The specific error is: ${e.message}`)}if(trigger.single){Triggers.delete(key)}}}}displayMonth(){return Clock.formatTwoDigits(this.month)}displayHour(){return Clock.formatTwoDigits(this.hour)}displayDay(){return Clock.formatTwoDigits(this.day)}displayMinute(){return Clock.formatTwoDigits(this.minute)}get weekday(){const date=new Date(this.year,this.month-1,this.day);return date.getDay()}get weekdayChs(){return Clock.weekdays[this.weekday]}static isLeapYear(year){return year%4===0&&year%100!==0||year%400===0}static formatTwoDigits(num){return num.toString().padStart(2,"0")}clone(){return new Clock(this.year,this.month,this.day,this.hour,this.minute)}toJSON(){return Serial.createReviver(String.format("new {0}({1},{2},{3},{4},{5})",this.constructor.name,JSON.stringify(this.year),JSON.stringify(this.month),JSON.stringify(this.day),JSON.stringify(this.hour),JSON.stringify(this.minute)))}}Macro.add("newclock",{handler(){const args=this.args;const num=index=>{const parsed=parseInt(args[index]);return isNaN(parsed)?undefined:parsed};if(!State.getVar(Clock.varName))State.setVar("$clock",new Clock(num(0),num(1),num(2),num(3),num(4)))}});Macro.add("addminutes",{handler(){if(this.args.length<1){return this.error("Not enough arguments provided. At least two arguments are required.")}const minutes=Number(this.args[0]);if(isNaN(minutes)){return this.error("Expected a number but received: "+typeof this.args[0])}const clock=State.getVar(Clock.varName);clock.addMinutes(minutes)}});Macro.add("addhours",{handler(){if(this.args.length<1){return this.error("Not enough arguments provided. At least one argument is required.")}const hours=Number(this.args[0]);if(isNaN(hours)){return this.error("Expected a number but received: "+typeof this.args[0])}const clock=State.getVar(Clock.varName);clock.addHours(hours)}});Macro.add("adddays",{handler(){if(this.args.length<1){return this.error("Not enough arguments provided. At least one argument is required.")}const days=Number(this.args[0]);if(isNaN(days)){return this.error("Expected a number but received: "+typeof this.args[0])}const clock=State.getVar(Clock.varName);clock.addDays(days)}});Macro.add("addmonths",{handler(){if(this.args.length<1){return this.error("Not enough arguments provided. At least one argument is required.")}const months=Number(this.args[0]);if(isNaN(months)){return this.error("Expected a number but received: "+typeof this.args[0])}const clock=State.getVar(Clock.varName);clock.addMonths(months)}});Macro.add("addyears",{handler(){if(this.args.length<1){return this.error("Not enough arguments provided. At least one argument is required.")}const years=Number(this.args[0]);if(isNaN(years)){return this.error("Expected a number but received: "+typeof this.args[0])}const clock=State.getVar(Clock.varName);clock.addYears(years)}});Macro.add("ftime",{handler(){const clock=State.getVar(Clock.varName);$(this.output).wiki(clock.getFormattedTime())}});Macro.add("fhour",{handler(){const clock=State.getVar(Clock.varName);$(this.output).wiki(clock.displayHour())}});Macro.add("fminute",{handler(){const clock=State.getVar(Clock.varName);$(this.output).wiki(clock.displayMinute())}});Macro.add("fday",{handler(){const clock=State.getVar(Clock.varName);$(this.output).wiki(clock.displayDay())}});Macro.add("fmonth",{handler(){const clock=State.getVar(Clock.varName);$(this.output).wiki(clock.displayMonth())}});Macro.add("fyear",{handler(){const clock=State.getVar(Clock.varName);$(this.output).wiki(clock.year)}});Macro.add("weekday",{handler(){const clock=State.getVar(Clock.varName);$(this.output).wiki(clock.weekdayChs)}});setup.Trigger=Trigger;window.Trigger=window.Trigger||Trigger;setup.Clock=Clock;window.Clock=window.Clock||Clock})();
/* End Clock Macro */ 